  T["CDI Clinical Evidence Framework"]

  A["Evidence Review&lt;br/&gt;&lt;span style='font-size:15px'&gt;Study Evaluation &amp; Bias Assessment&lt;/span&gt;"]
  B["Risk-Benefit&lt;br/&gt;Evaluation&lt;br/&gt;&lt;span style='font-size:15px'&gt;Assess Safety vs Benefit&lt;/span&gt;"]
  C["Clinical Context&lt;br/&gt;&amp; Intended Use&lt;br/&gt;&lt;span style='font-size:15px'&gt;Define Population and Use Case&lt;/span&gt;"]
  D["Equivalence&lt;br/&gt;&amp; Justification&lt;br/&gt;&lt;span style='font-size:15px'&gt;Compare with Existing Devices&lt;/span&gt;"]
  E["Synthesis&lt;br/&gt;&amp; Interpretation&lt;br/&gt;&lt;span style='font-size:15px'&gt;Integrate Evidence into Clinical Meaning&lt;/span&gt;"]

  F["Demonstrate&lt;br/&gt;&lt;b&gt;Clinically Meaningful&lt;/b&gt;&lt;br/&gt;Benefit"]
  G["Defensible Clinical Claims&lt;br/&gt;&lt;span style='font-size:15px'&gt;Valid | Relevant | Justifiable | Reproducible&lt;/span&gt;"]

  T --&gt; A

  A --&gt; B
  B --&gt; C
  C --&gt; D
  D --&gt; E
  E --&gt; A

  A --- F
  B --- F
  C --- F
  D --- F
  E --- F

  F --&gt; G

